// src/components/Dashboard.js
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

function Dashboard() {
  const [role, setRole] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    const storedRole = localStorage.getItem('role');
    if (!storedRole) {
      // If no role is found, redirect to login page
      navigate('/login');
    } else {
      setRole(storedRole);
    }
  }, [navigate]);

  return (
    <div>
      <h2>Dashboard</h2>
      {role === 'Manager' && (
        <div>
          <h3>Manager Dashboard</h3>
          <ul>
            <li><a href="/employee-dashboard">Employee</a></li>
            <li><a href="/company-dashboard">Company</a></li>
            <li><a href="/records-dashboard">Records</a></li>
          </ul>
        </div>
      )}
      {role === 'Employee' && (
        <div>
          <h3>Employee Dashboard</h3>
          <ul>
            <li><a href="/work-entry">Work Entry</a></li>
            <li><a href="/work-details">Work Details</a></li>
            <li><a href="/create-company">Create Company</a></li>
          </ul>
        </div>
      )}
    </div>
  );
}

export default Dashboard;
